#include <stdio.h>
#include <time.h>
#include <stdlib.h>

int main() {
    // Read optional T
    char buffer[64];
    int T = 1;
    if (fgets(buffer, sizeof(buffer), stdin) != NULL) {
        char *endptr;
        long val = strtol(buffer, &endptr, 10);
        if (endptr != buffer && *endptr == '\n') {
            T = (int)val;
        } else {
            // No integer on first line, treat as no input
            T = 1;
        }
    }
    // Get current time
    time_t now = time(NULL);
    struct tm tm = *localtime(&now);
    char weekStr[3]; // "%V" produces two digits plus null terminator
    strftime(weekStr, sizeof(weekStr), "%V", &tm);
    for (int i = 0; i < T; ++i) {
        printf("%s", weekStr);
        if (i + 1 < T) printf("\n");
    }
    return 0;
}

