function isoWeek(date) {
  const target = new Date(date.valueOf());
  const dayNr = (date.getDay() + 6) % 7; // Monday=0
  target.setDate(target.getDate() - dayNr + 3);
  const firstThursday = target.valueOf();
  const yearStart = new Date(target.getFullYear(), 0, 1);
  const firstDayNr = (yearStart.getDay() + 6) % 7;
  const firstThursdayOfYear = new Date(yearStart);
  firstThursdayOfYear.setDate(yearStart.getDate() + ((3 - firstDayNr + 7) % 7));
  const weekNo = 1 + Math.round((firstThursday - firstThursdayOfYear) / 604800000);
  return weekNo;
}
